// IMPROVEMENT: Deduplication - Filter out articles that already exist in Notion
const newArticles = $('Merge').all();
const existingArticles = $('Fetch Recent Articles').all();

// Build a Set of existing URLs for O(1) lookup
const existingUrls = new Set();
for (const existing of existingArticles) {
  if (existing.json.properties?.URL?.url) {
    existingUrls.add(existing.json.properties.URL.url);
  }
}

// Filter to only new articles
const uniqueArticles = [];
let duplicateCount = 0;

for (const article of newArticles) {
  if (!existingUrls.has((article.json.url || article.json.link))) {
    uniqueArticles.push(article);
  } else {
    duplicateCount++;
    console.log(`Skipping duplicate: ${article.json.title}`);
  }
}

console.log(`Deduplication: ${duplicateCount} duplicates filtered, ${uniqueArticles.length} new articles to process`);

if (uniqueArticles.length === 0) {
  // Return empty to stop workflow gracefully
  return [];
}

return uniqueArticles;

// IMPROVED: Enhanced validation with better error handling and fallback behavior
const outputItems = [];
const errorItems = [];

// Define the expected JSON schema
const ALLOWED_LABELS = new Set([
  'Governance', 'Risk', 'Compliance', 'Awareness', 'Training', 'Career',
  'Leadership', 'Framework', 'Audit', 'Privacy', 'DataProtection', 'CloudSecurity',
  'Incident', 'Breach', 'Regulation', 'Policy', 'Metrics', 'Vendor', 'ThirdParty',
  'BusinessContinuity', 'DisasterRecovery', 'Communication', 'Stakeholder',
  'Budget', 'ROI', 'Automation', 'AITools', 'Standards', 'ISO', 'NIST', 'SOC', 'GDPR'
]);

const ALLOWED_RATINGS = new Set(['S Tier', 'A Tier', 'B Tier', 'C Tier', 'D Tier']);

const REQUIRED_FIELDS = [
  'one-sentence-summary', 'labels', 'rating', 
  'rating-explanation', 'quality-score', 'quality-score-explanation'
];

function createFallbackData(title, error) {
  return {
    'one-sentence-summary': `Processing error for: ${title?.substring(0, 100) || 'Unknown article'}`,
    'labels': 'Risk',
    'rating': 'D Tier',
    'rating-explanation': `- Processing failed: ${error}\n- Manual review recommended\n- Article may still be valuable\n- Check original source\n- Retry later if transient error`,
    'quality-score': 1,
    'quality-score-explanation': '- Automated processing failed\n- Score set to minimum\n- Manual review needed\n- Not a reflection of content quality\n- Technical error only'
  };
}

function validateAndSanitize(data) {
  // Check for required fields - use fallback for missing
  for (const field of REQUIRED_FIELDS) {
    if (!(field in data)) {
      console.log(`WARNING: Missing field '${field}', using default`);
      if (field === 'one-sentence-summary') data[field] = 'Summary not available';
      else if (field === 'labels') data[field] = '';
      else if (field === 'rating') data[field] = 'D Tier';
      else if (field === 'rating-explanation') data[field] = 'Rating explanation not available';
      else if (field === 'quality-score') data[field] = 1;
      else if (field === 'quality-score-explanation') data[field] = 'Score explanation not available';
    }
  }

  // Check for unexpected fields (potential injection)
  const allowedFields = new Set(REQUIRED_FIELDS);
  for (const key of Object.keys(data)) {
    if (!allowedFields.has(key)) {
      console.log(`WARNING: Unexpected field detected and removed: ${key}`);
      delete data[key];
    }
  }

  // Validate rating
  if (!ALLOWED_RATINGS.has(data.rating)) {
    console.log(`WARNING: Invalid rating '${data.rating}', defaulting to 'D Tier'`);
    data.rating = 'D Tier';
  }

  // Validate quality-score
  const score = parseInt(data['quality-score'], 10);
  if (isNaN(score) || score < 1 || score > 100) {
    console.log(`WARNING: Invalid quality-score '${data['quality-score']}', defaulting to 1`);
    data['quality-score'] = 1;
  } else {
    data['quality-score'] = score;
  }

  // Validate and sanitize labels
  if (typeof data.labels === 'string' && data.labels.trim() !== '') {
    const labelList = data.labels.split(',').map(l => l.trim());
    const validLabels = labelList.filter(label => {
      if (ALLOWED_LABELS.has(label)) {
        return true;
      } else {
        console.log(`WARNING: Invalid label removed: ${label}`);
        return false;
      }
    });
    data.labels = validLabels.join(', ');
  }

  // Sanitize string fields (prevent any remaining injection attempts)
  if (typeof data['one-sentence-summary'] === 'string') {
    data['one-sentence-summary'] = data['one-sentence-summary'].substring(0, 500);
  }
  if (typeof data['rating-explanation'] === 'string') {
    data['rating-explanation'] = data['rating-explanation'].substring(0, 2000);
  }
  if (typeof data['quality-score-explanation'] === 'string') {
    data['quality-score-explanation'] = data['quality-score-explanation'].substring(0, 2000);
  }

  return data;
}

// FIX: Get all Merge items upfront to avoid pairedItem issues in loop
let mergeItems = [];
try {
  mergeItems = $('Merge').all();
  console.log(`Successfully retrieved ${mergeItems.length} items from Merge node`);
} catch (e) {
  console.log(`WARNING: Could not access Merge node: ${e.message}`);
}

// Process each input item
const inputItems = $input.all();
for (let i = 0; i < inputItems.length; i++) {
  const item = inputItems[i];
  const response = item.json;

  try {
    // Initialize variable for the text content
    let textContent;

    // Check if we have a content array (Anthropic API response format)
    if (response.content && Array.isArray(response.content)) {
      const textItem = response.content.find(item => item.type === 'text' && item.text);
      if (textItem && textItem.text) {
        textContent = textItem.text;
      } else {
        throw new Error('No text content found in response array');
      }
    }
    else if (typeof response.content === 'string') {
      textContent = response.content;
    }
    else if (typeof response === 'string') {
      textContent = response;
    }
    else {
      throw new Error('Unable to find text content in response');
    }

    // Try to extract JSON from markdown code blocks if present
    const jsonMatch = textContent.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (jsonMatch) {
      textContent = jsonMatch[1].trim();
    }

    // Parse the JSON string
    let parsedData;
    try {
      parsedData = JSON.parse(textContent);
    } catch (parseError) {
      console.log('JSON parse failed, attempting to extract JSON object');
      // Try to find JSON object in the text
      const objectMatch = textContent.match(/\{[\s\S]*\}/);
      if (objectMatch) {
        parsedData = JSON.parse(objectMatch[0]);
      } else {
        throw new Error(`Invalid JSON: ${parseError.message}`);
      }
    }

    // Validate and sanitize the parsed data
    const validatedData = validateAndSanitize(parsedData);

    // FIX: Get original article metadata safely using index-based access
    let mergeData = {};
    try {
      // Try index-based access first (more reliable than pairedItem)
      if (mergeItems[i]) {
        mergeData = mergeItems[i].json || {};
        console.log(`Got Merge data for item ${i}: ${mergeData.title?.substring(0, 50)}`);
      } else {
        console.log(`WARNING: No Merge item at index ${i}, will use empty metadata`);
      }
    } catch (e) {
      console.log(`WARNING: Could not access Merge item ${i}: ${e.message}`);
    }

    outputItems.push({ 
      json: {
        ...validatedData,
        title: mergeData.title || 'Unknown Title',
        url: mergeData.url || '',
        pubDate: mergeData.pubDate || '',
        source: mergeData.source || 'Unknown Source'
      }
    });
  } catch (error) {
    console.log(`Processing error for item ${i}: ${error.message}`);
    // IMPROVEMENT: Instead of failing, create a fallback entry
    let title = 'Unknown';
    try {
      if (mergeItems[i]) {
        title = mergeItems[i].json?.title;
      }
    } catch (e) {}

    const fallbackData = createFallbackData(title, error.message);
    outputItems.push({ json: fallbackData });
  }
}

return outputItems;

// IMPROVEMENT: Workflow execution summary
const timestamp = new Date().toISOString();
const processedCount = $input.all().length;

console.log(`\n========================================`);
console.log(`GRC News Assistant - Execution Summary`);
console.log(`Timestamp: ${timestamp}`);
console.log(`Articles processed: ${processedCount}`);
console.log(`========================================\n`);

return $input.all();
